instruction:
`ofstream` opens a file for writing. Use `<<` just like `cout`:

```cpp
ofstream file("output.txt");
file << "Hello" << endl;
// file closed automatically when it goes out of scope
```

`ios::app` appends instead of overwriting.

starter:
#include <iostream>
#include <fstream>
#include <string>
using namespace std;

int main() {
    // Write to file:
    {
        ofstream out("students.txt");
        if (!out) { cerr << "Cannot create file!" << endl; return 1; }

        out << "Alice,90" << endl;
        out << "Bob,85" << endl;
        out << "Carol,92" << endl;
        cout << "Written 3 records." << endl;
    }  // file closed here

    // Append to file:
    {
        ofstream out("students.txt", ios::app);
        out << "David,78" << endl;
        cout << "Appended 1 record." << endl;
    }

    return 0;
}

#include <iostream>
#include <fstream>
#include <string>
#include <sstream>
using namespace std;

int main() {
    // First create the file:
    {
        ofstream out("data.txt");
        out << "Alice,90" << endl << "Bob,85" << endl << "Carol,92" << endl;
    }

    // Read it back:
    ifstream in("data.txt");
    if (!in) { cerr << "File not found!" << endl; return 1; }

    string line;
    int count = 0;
    double total = 0;

    while (getline(in, line)) {
        count++;
        stringstream ss(line);
        string name;
        int score;
        getline(ss, name, ',');
        ss >> score;
        cout << name << " scored " << score << endl;
        total += score;
    }

    cout << "Average: " << total / count << endl;

    return 0;
}

#include <iostream>
#include <fstream>
#include <string>
#include <map>
using namespace std;

int main() {
    // Write test data:
    {
        ofstream out("words.txt");
        out << "the quick brown fox the fox the" << endl;
    }

    // Count word frequency:
    ifstream in("words.txt");
    map<string, int> freq;
    string word;

    while (in >> word) {
        freq[word]++;
    }

    for (const auto& [w, c] : freq) {
        cout << w << ": " << c << endl;
    }

    return 0;
}

#include <iostream>
#include <fstream>
using namespace std;

int main() {
    ifstream file("nonexistent_file.txt");

    if (!file.is_open()) {
        cerr << "Error: could not open file" << endl;
    }

    cout << "good(): " << boolalpha << file.good() << endl;
    cout << "fail(): " << file.fail() << endl;

    // Reset and try a real file:
    ofstream out("test.txt");
    out << "Hello" << endl;
    out.close();

    ifstream in("test.txt");
    cout << "File opened: " << in.is_open() << endl;
    string line;
    getline(in, line);
    cout << line << endl;

    return 0;
}

#include <iostream>
#include <fstream>
#include <filesystem>
using namespace std;
namespace fs = filesystem;

int main() {
    // Create a directory and file:
    fs::create_directories("myapp/data");
    ofstream out("myapp/data/config.txt");
    out << "port=8080" << endl << "host=localhost" << endl;
    out.close();

    fs::path p("myapp/data/config.txt");
    cout << "Exists: " << boolalpha << fs::exists(p) << endl;
    cout << "Size: "   << fs::file_size(p) << " bytes" << endl;
    cout << "Name: "   << p.filename() << endl;
    cout << "Parent: " << p.parent_path() << endl;

    // Cleanup:
    fs::remove_all("myapp");
    cout << "Cleaned up." << endl;

    return 0;
}
